#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int n; cin >> n;
    for (int i = 0; i < n; i++) {
        unsigned int x; cin >> x;
        cout << __builtin_popcount(x) << "\n";
    }
    return 0;
}
